import{_ as l,o as i,c as r,a2 as e}from"./chunks/framework.Cr-Z7ngm.js";const p=JSON.parse('{"title":"交易红包","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"rewards/trading-red-packet.md","filePath":"zh-CN/rewards/trading-red-packet.md"}'),t={name:"rewards/trading-red-packet.md"};function o(n,a,d,s,h,u){return i(),r("div",null,[...a[0]||(a[0]=[e('<h1 id="交易红包" tabindex="-1">交易红包 <a class="header-anchor" href="#交易红包" aria-label="Permalink to &quot;交易红包&quot;">​</a></h1><p>交易红包活动（Trade Bonus Activity）是 LongBridge 平台针对活跃交易用户推出的奖励活动。用户在活动期间完成指定的交易任务（如累计交易金额、交易笔数等），系统自动发放现金红包或交易券奖励。交易红包活动旨在激励用户活跃交易，奖励以自动化方式发放，用户无需手动申领。</p><h2 id="参与条件" tabindex="-1">参与条件 <a class="header-anchor" href="#参与条件" aria-label="Permalink to &quot;参与条件&quot;">​</a></h2><ul><li>持有有效的 LongBridge 证券账户</li><li>已完成实名认证（KYC），账户状态正常</li><li>账户所属地区/持牌人在活动覆盖范围内</li><li>部分活动可能要求账户持仓达到一定金额门槛</li></ul><h2 id="红包类型" tabindex="-1">红包类型 <a class="header-anchor" href="#红包类型" aria-label="Permalink to &quot;红包类型&quot;">​</a></h2><p>同一活动可能同时配置多种红包类型：</p><ul><li>普通红包（Red Packet）：完成成交任务后系统自动触发，奖励直接发放</li><li>彩蛋红包（Surprise Reward）：随机触发，并非每笔成交都能获得；有库存上限，发完为止；部分活动限定整个活动周期内每人只能获得一个彩蛋；彩蛋类型受用户分群过滤，不在分群内的用户不会触发</li><li>分享红包（Share Reward）：成交后获得&quot;分享奖励&quot;，需分享给好友才能领取更大价值；未被好友领取的部分可能以较低价值&quot;反还&quot;给原用户；分享奖励中区分新用户奖励和普通奖励</li></ul><h2 id="任务类型" tabindex="-1">任务类型 <a class="header-anchor" href="#任务类型" aria-label="Permalink to &quot;任务类型&quot;">​</a></h2><ul><li>单笔交易任务：单笔成交金额达到指定金额（如单笔成交 5,000 港币）</li><li>累计交易笔数任务：活动期间内累计完成 N 笔有效成交</li><li>累计交易金额任务：活动期间内累计成交金额达到指定门槛</li><li>特定品种交易任务：交易指定市场（港股/美股）或指定股票/ETF</li><li>阶梯交易任务：完成不同档位的交易量获取对应档位的奖励</li></ul><h2 id="参与步骤" tabindex="-1">参与步骤 <a class="header-anchor" href="#参与步骤" aria-label="Permalink to &quot;参与步骤&quot;">​</a></h2><ol><li>在「活动中心」找到当期交易红包活动并查看活动规则</li><li>确认账户符合参与条件</li><li>在活动有效期内完成指定的交易任务</li><li>系统自动检测任务完成情况，无需手动申领</li><li>奖励自动发放，可在「活动中心 → 我的奖励」查看奖励状态</li></ol><h2 id="任务完成判定" tabindex="-1">任务完成判定 <a class="header-anchor" href="#任务完成判定" aria-label="Permalink to &quot;任务完成判定&quot;">​</a></h2><ul><li>以最终有效成交为准，委托挂单未成交不计入进度</li><li>撤单（已撤销的委托）不计入交易任务进度</li><li>废单（因系统原因拒绝的委托）不计入</li><li>活动期间内完成的成交才算有效，活动开始前或结束后的成交不计入</li><li>交易进度通常实时更新，可在活动页面查看当前进度</li></ul><h2 id="奖励类型" tabindex="-1">奖励类型 <a class="header-anchor" href="#奖励类型" aria-label="Permalink to &quot;奖励类型&quot;">​</a></h2><ul><li>现金红包：直接发放至账户可用现金余额（港币、人民币或美元，以活动说明为准）</li><li>交易券（手续费券）：用于抵扣下次交易的手续费</li><li>现金券：满足条件可在平台内使用</li><li>体验金：有使用期限的模拟资金，不可直接提现</li></ul><h2 id="发放时机" tabindex="-1">发放时机 <a class="header-anchor" href="#发放时机" aria-label="Permalink to &quot;发放时机&quot;">​</a></h2><p>交易红包是全自动发放流程，系统检测到交易任务完成后自动触发，无需用户主动操作。通常在任务完成后的 1-3 个工作日内完成发放。部分交易红包采用 T+1 批量发放：系统每天香港时间 16:30 检查前一日达标情况后统一发放，当天达标的奖励须等到次日 16:30 后才会处理。阶梯奖励按每个档位单独触发，达到一档发一档。</p><h2 id="奖励状态说明" tabindex="-1">奖励状态说明 <a class="header-anchor" href="#奖励状态说明" aria-label="Permalink to &quot;奖励状态说明&quot;">​</a></h2><p>待发放（Pending）：交易任务已确认，奖励排队等待发放，无需操作，等待系统处理。发放中（Sending）：系统正在将红包发送至账户，稍等片刻，通常数分钟至数小时完成。已发放（Sent）：红包已成功到账，可在账户余额中查看和使用。锁定中（Lockup）：红包已到账但处于锁定期，等待锁定期结束，系统自动解锁。已解锁可用（Used）：锁定期结束，红包已可使用。发放失败（Failed）：红包发放失败，联系客服，提供奖励详情协助处理。已取消（Cancel）：红包因规则原因被取消，联系客服确认原因。</p><h2 id="红包领取与使用答疑" tabindex="-1">红包领取与使用答疑 <a class="header-anchor" href="#红包领取与使用答疑" aria-label="Permalink to &quot;红包领取与使用答疑&quot;">​</a></h2><p><strong>Q：我完成了交易任务，为什么红包还没到账？</strong><br> A：交易红包采用自动发放机制，任务完成后通常在 1-3 个工作日内到账。您可以在「活动中心 → 我的奖励」查看奖励状态。若状态显示「待发放（Pending）」或「发放中（Sending）」说明正在处理中，请耐心等待。若超过 3 个工作日仍显示未发放，请联系客服。</p><p><strong>Q：交易红包自动发放是什么意思？我需要做什么？</strong><br> A：交易红包发放是全自动流程，您完成交易任务后系统会自动检测并触发发放，无需您手动点击领取或申请。您只需正常完成交易即可，奖励会自动出现在「我的奖励」列表中，发放成功后可在账户余额中找到。</p><p><strong>Q：我下了委托单但还没成交，这算完成任务了吗？</strong><br> A：不算。交易红包活动以最终有效成交为判定标准，仅挂单（委托挂出但未成交）不计入任务进度。只有当您的委托单实际成交后，才会计入交易任务进度。部分交易较难立即成交（如限价单远离市价），建议关注委托成交情况。</p><p><strong>Q：我的一笔交易后来被撤销了，还算任务进度吗？</strong><br> A：不算。已撤销的委托不计入交易任务进度。只有最终有效成交的交易才会累计到活动任务中。如果您撤销了委托，该笔交易量将从进度中扣除（如已计入）或不予计入。</p><p><strong>Q：奖励显示「发放失败（Failed）」怎么办？</strong><br> A：发放失败可能由以下原因导致：（1）账户 KYC 未完成；（2）账户被冻结或存在异常；（3）系统技术问题。请先检查您的账户状态，确保实名认证正常完成。然后联系客服，提供您的账户信息和奖励相关截图，客服会协助排查并重新触发发放。</p><p><strong>Q：活动期间我做了很多交易，为什么只收到部分红包？</strong><br> A：可能的原因：（1）部分交易发生在活动有效期之外（活动开始前或结束后）；（2）部分委托虽挂出但未实际成交；（3）阶梯奖励中您只完成了部分档位的任务；（4）若活动有彩蛋红包，彩蛋不保证每笔成交都触发，且有库存限制和活动内次数上限。建议在活动页面查看当前任务进度，确认哪些交易被计入。如仍有疑问请联系客服核查。</p><p><strong>Q：彩蛋红包是什么？为什么有时候成交后弹出彩蛋，有时候没有？</strong><br> A：彩蛋红包是交易红包活动中的随机惊喜奖励，不保证每笔成交都触发。彩蛋有一定触发概率，且总库存有限，发完即止。部分活动还限制每位用户整个活动周期内只能获得一个彩蛋。彩蛋也可能有用户分群限制，不在指定范围内的用户不会触发。如果您长时间未触发彩蛋，可能是库存已耗尽或您不在彩蛋覆盖范围内。</p><p><strong>Q：什么是分享红包？分享给好友有什么好处？</strong><br> A：分享红包是部分交易红包活动中的特殊奖励机制。您成交后会获得一个&quot;分享奖励&quot;，将其分享链接发给好友，好友可以领取其中的部分价值，而您也能获得相应奖励。若好友未领取，剩余价值可能以折扣形式反还给您。分享红包中对新用户（未注册的好友）通常有额外加成奖励。具体分享规则和奖励分配比例以活动详情页说明为准。</p><p><strong>Q：交易红包可以直接提现吗？</strong><br> A：这取决于具体奖励类型。现金红包通常可以直接使用或提现（以活动规则为准）；交易券只能用于抵扣手续费；体验金通常不可直接提现，有特定使用规则。具体奖励的使用条件请查看奖励详情或活动说明。</p><p><strong>Q：活动结束了，我才想起来还有一笔交易没结算完，算吗？</strong><br> A：通常不算。活动以「活动截止时刻前完成的最终有效成交」为统计依据。活动结束后才最终成交（含活动结束时刻后才完成清算）的交易一般不计入活动进度。建议在活动结束前确认所有委托单的成交状态。如有特殊情况请联系客服确认。</p><h2 id="红包使用限制与过期规则" tabindex="-1">红包使用限制与过期规则 <a class="header-anchor" href="#红包使用限制与过期规则" aria-label="Permalink to &quot;红包使用限制与过期规则&quot;">​</a></h2><ul><li>交易红包是全自动发放，无需手动领取</li><li>挂单未成交、已撤销委托均不计入任务进度</li><li>所有活动时间以香港时间（HKT，UTC+8）为准</li><li>交易成交时间必须在活动有效期内</li><li>各类奖励均有使用期限，过期未使用的奖励自动进入 Cancel 状态，不做补偿</li><li>建议在交易前先确认活动规则，了解哪些交易品种和市场在活动统计范围内</li><li>奖励查看路径：APP「活动中心 → 我的奖励」</li></ul>',32)])])}const b=l(t,[["render",o]]);export{p as __pageData,b as default};
